class Solution:
    def minimumOperations(self, grid):
        ops = 0
        for col in zip(*grid):
            prev = col[0]
            for v in col[1:]:
                if v > prev:
                    prev = v
                else:
                    need = prev + 1
                    ops += need - v
                    prev = need
        return ops

