class Solution:
    def minimumOperations(self, grid):
        m = len(grid)
        n = len(grid[0])
        ops = 0
        for j in range(n):
            prev = grid[0][j]
            for i in range(1, m):
                cur = grid[i][j]
                if cur <= prev:
                    ops += prev + 1 - cur
                    prev += 1
                else:
                    prev = cur
        return ops

