var minimumOperations = function(grid) {
    const m = grid.length;
    const n = grid[0].length;
    let ops = 0;
    for (let j = 0; j < n; j++) {
        let prev = grid[0][j];
        for (let i = 1; i < m; i++) {
            const cur = grid[i][j];
            if (cur <= prev) {
                ops += prev + 1 - cur;
                prev += 1;
            } else {
                prev = cur;
            }
        }
    }
    return ops;
};
